Scripts.OnDragStart:
if getglobal('TWTMainLockButtonNT'):GetTexture() == 'Interface\\addons\\TWThreat\\images\\icon_unlocked'
then
this:StartMoving();
this.isMoving = true;
end

Scripts.OnEnter:
GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('打开设置');
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('锁定/解锁窗口')
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('关闭窗口');
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('Close Window');
GameTooltip:Show();

GameTooltip:ClearLines();
